import React, { useEffect, useState } from "react";
import { productAPI } from "../api";
import ProductGrid from "../components/product/ProductGrid";

const Home = () => {
  const [products, setProducts] = useState([]);

  useEffect(() => {
    let mounted = true;
    productAPI.getProducts({ limit: 8 }).then(res => {
      if (mounted) setProducts(res.data || []);
    }).catch(err => console.error(err));
    return () => mounted = false;
  }, []);

  return (
    <div>
      <section className="banner" style={{
        height: 480,
        backgroundImage: "url('https://i.pinimg.com/1200x/4f/ea/51/4fea51b444caa855e8c6a2e705ffaaf5.jpg')",
        backgroundSize: "cover",
        backgroundPosition: "center",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        color: "#fff"
      }}>
        <div style={{ textAlign: "center", background: "rgba(0,0,0,0.28)", padding: 20, borderRadius: 8 }}>
          <h1 style={{ fontFamily: "Playfair Display, serif", fontSize: 44 }}>Where Every Bloom Tells a Story</h1>
          <button style={{ marginTop: 12, background: "#e06c7f", color: "#fff", padding: "12px 24px", border: "none", borderRadius: 25 }}>Shop Collection</button>
        </div>
      </section>

      <section style={{ padding: "48px 10%" }}>
        <h2 style={{ textAlign: "center", fontFamily: "Playfair Display, serif", color: "#e06c7f" }}>Featured Products</h2>
        <div style={{ marginTop: 20 }}>
          <ProductGrid products={products.length ? products : Array.from({length:5}).map((_,i)=>({ _id: `p${i}`, name: "Sản phẩm mẫu", price: 0 }))} />
        </div>
      </section>
    </div>
  );
};

export default Home;
